const AddressUpdateItemView  = ({ data,  itm, active, confirm }) => {
	const [obs, set_obs] = useState(1);


	
	
	
	const updFrm = (f, v, k) => {
		let frm2 = getStore(frmNm) || {};
		if(k){
			if( !frm2[k]){
				frm2[k] = {};
			}
			frm2[k][f] = v;
		}else{
			frm2[f] = v;
		}
		updStore(frmNm, frm2);
		
		set_obs(gen16CodeId())
	};


	const print  = async ()  => {
		let ffm = getStore(frmNm);
		confirm && confirm(ffm);
		close();
	};





	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID})
	}



	
	let flds = [
		"addressLineOne",
		"addressLineTwo",
		"city",
		"state",
		"country",
		"zipcode",
		"fromDate",
		"toDate"
	]

	let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )



	return(
		<div style={{
			maxHeight: "80vh",
			width: "960px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px 32px",

		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					Actualizar Direccion
				</p>
				<div className="flexSpace"/>
				
			</div>
			

			
			

			<div className="_dsplFlx spaceAround">
				<TextInput  
					init={getStore(frmNm)?.["country"]} 
					label={"Pais"} 
					width={260} 
					updChanges={(e)=>updFrm("country",e)}
				/>
				
			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{marginTop: 20}}> 
				<TextInput 
					init={getStore(frmNm)?.["addressLineOne"]} 
					label={"Calle "} 
					width={520} 
					updChanges={(e)=>updFrm("addressLineOne",e)}
				/>
				<TextInput 
					init={getStore(frmNm)?.["addressLineTwo"]} 
					label={"Apt (optional)"} 
					width={180} 
					updChanges={(e)=>updFrm("addressLineTwo",e)}
				/>

			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{marginTop: 20}}> 

				<TextInput 
					init={getStore(frmNm)?.["city"]} 
					label={"Ciudad o Municipio"} 
					width={200} 
					updChanges={(e)=>updFrm("city",e)}
				/>
			
            
				<TextInput  
					init={getStore(frmNm)?.["state"]} 
					label={"Estado o Provincia"} 
					width={200} 
					updChanges={(e)=>updFrm("state",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["zipcode"]} 
					label={"Codigo Postal"} 
					width={90} 
					updChanges={(e)=>updFrm("zipcode",e)}
				/>
			</div>

			<div className="_dsplFlx spaceAround flxWrp" style={{marginTop:24}}> 
				<TextInput  
					init={getStore(frmNm)?.["fromDate"]?.["month"]} 
					label={"Desde (Month)"} 
					width={90} 
					updChanges={(e)=>updFrm("month",e, "fromDate")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["fromDate"]?.["year"]} 
					label={"Desde (Year)"} 
					width={120} 
					updChanges={(e)=>updFrm("year",e, "fromDate")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["toDate"]?.["month"]} 
					label={"Hasta (Month)"} 
					width={90} 
					updChanges={(e)=>updFrm("month",e, "toDate")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["toDate"]?.["year"]} 
					label={"Hasta (Year)"} 
					width={120} 
					updChanges={(e)=>updFrm("year",e, "toDate")}
				/>
			</div>
			
			
			{diff?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={print}/>
						
					</div>
				</div>
			):<div className="card"/>}


		</div>
	)

}










